Here are comprehensive pytest-style unit tests for the `compose` function:

```python
import pytest
from compose import compose  # adjust import to match your module name


# --- Helpers ---

def double(x):
    return x * 2

def increment(x):
    return x + 1

def square(x):
    return x ** 2

def negate(x):
    return -x

def to_string(x):
    return str(x)

def to_upper(s):
    return s.upper()

def strip(s):
    return s.strip()

def add_exclamation(s):
    return s + "!"


# --- Happy Path ---

class TestComposeTwoFunctions:
    def test_applies_rightmost_function_first(self):
        fn = compose(double, increment)  # double(increment(x))
        assert fn(3) == 8  # increment(3)=4, double(4)=8

    def test_applies_leftmost_function_last(self):
        fn = compose(increment, double)  # increment(double(x))
        assert fn(3) == 7  # double(3)=6, increment(6)=7

    def test_order_matters(self):
        fn1 = compose(double, increment)
        fn2 = compose(increment, double)
        assert fn1(5) != fn2(5)


class TestComposeThreeFunctions:
    def test_three_numeric_functions(self):
        fn = compose(negate, double, increment)  # negate(double(increment(x)))
        assert fn(3) == -8  # increment(3)=4, double(4)=8, negate(8)=-8

    def test_three_string_functions(self):
        fn = compose(add_exclamation, to_upper, strip)
        assert fn("  hello  ") == "HELLO!"

    def test_mixed_type_transformation(self):
        fn = compose(to_upper, to_string, double)
        assert fn(5) == "10"  # double(5)=10, to_string(10)="10", to_upper("10")="10"


class TestComposeSingleFunction:
    def test_single_function_behaves_as_identity_wrapper(self):
        fn = compose(double)
        assert fn(4) == 8

    def test_single_function_string(self):
        fn = compose(to_upper)
        assert fn("hello") == "HELLO"


class TestComposeReturnValue:
    def test_returns_callable(self):
        fn = compose(double, increment)
        assert callable(fn)

    def test_can_be_called_multiple_times(self):
        fn = compose(double, increment)
        assert fn(1) == 4
        assert fn(2) == 6
        assert fn(0) == 2

    def test_composed_function_can_be_composed_again(self):
        double_then_inc = compose(increment, double)
        fn = compose(square, double_then_inc)  # square(increment(double(x)))
        assert fn(3) == 49  # double(3)=6, increment(6)=7, square(7)=49


# --- Edge Cases ---

class TestComposeNoFunctions:
    def test_no_functions_returns_identity(self):
        fn = compose()
        assert fn(5) == 5

    def test_no_functions_with_string(self):
        fn = compose()
        assert fn("hello") == "hello"

    def test_no_functions_with_none(self):
        fn = compose()
        assert fn(None) is None

    def test_no_functions_with_list(self):
        fn = compose()
        result = fn([1, 2, 3])
        assert result == [1, 2, 3]


